import axios from 'axios';

const baseUrl = 'https://api.example.com'; // default to https for API calls

// Function to make a GET request to the API or local IoT device
async function fetchApiOrDeviceData(url) {
  try {
    const response = await axios.get(url, {
      headers: {
        Accept: 'application/json',
        'Content-Type': 'application/json'
      }
    });

    return response.data;
  } catch (error) {
    console.error('Error fetching data:', error);
    throw error;
  }
}

// Function to make a POST request to the API or local IoT device
async function postApiOrDeviceData(url, data) {
  try {
    const response = await axios.post(url, data, {
      headers: {
        Accept: 'application/json',
        'Content-Type': 'application/json'
      }
    });

    return response.data;
  } catch (error) {
    console.error('Error posting data:', error);
    throw error;
  }
}

// Function to make a request to an IoT device with HTTP or HTTPS
async function fetchIoTData(url, secure = true) {
  try {
    const protocol = secure ? 'https' : 'http';
    const response = await axios.get(`${protocol}://${url}`, {
      headers: {
        Accept: 'application/json',
        'Content-Type': 'application/json'
      }
    });

    return response.data;
  } catch (error) {
    console.error('Error fetching IoT data:', error);
    throw error;
  }
}